+/**
+ * Email notification handler — formats and dispatches email notifications
+ * for order lifecycle events.
+ *
+ * Integrates with the existing notification architecture using BOTH patterns:
+ * - EventBus subscription for order:created events
+ * - CallbackRegistry for order:status-changed events
+ *
+ * This mirrors how NotificationService registers its handlers (see
+ * notification.service.ts for the mixed-pattern discussion).
+ *
+ * Depends on:
+ * - EventBus (event system) for order creation events
+ * - CallbackRegistry (direct callbacks) for status change events
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
+import { statusChangeCallbacks } from '../utils/callback-registry.js';
+import { Logger } from '../utils/logger.js';
+
+export interface EmailMessage {
+  id: string;
+  to: string;
+  subject: string;
+  htmlBody: string;
+  plainBody: string;
+  createdAt: Date;
+}
+
+const STATUS_LABELS: Record<string, string> = {
+  pending: 'Pending',
+  confirmed: 'Confirmed',
+  shipped: 'Shipped',
+  delivered: 'Delivered',
+  cancelled: 'Cancelled',
+};
+
+let nextEmailId = 1;
+
+function generateEmailId(): string {
+  return `email-${String(nextEmailId++).padStart(4, '0')}`;
+}
+
+export function resetEmailIdCounter(): void {
+  nextEmailId = 1;
+}
+
+export class EmailNotificationHandler {
+  private logger = new Logger('EmailNotificationHandler');
+  private sentEmails: EmailMessage[] = [];
+
+  constructor(private eventBus: EventBus) {
+    this.registerHandlers();
+  }
+
+  /**
+   * Register event handlers following the existing dual-pattern approach.
+   */
+  private registerHandlers(): void {
+    // Pattern 1: EventBus subscription for order creation
+    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
+      this.handleOrderCreated(event);
+    });
+
+    // Pattern 2: CallbackRegistry for status changes
+    statusChangeCallbacks.register((event) => {
+      this.handleOrderStatusChanged(event);
+    });
+  }
+
+  /**
+   * Handle order created — send a welcome/confirmation email.
+   */
+  private handleOrderCreated(event: OrderCreatedEvent): void {
+    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);
+
+    const itemRows = event.order.items
+      .map(
+        (item) =>
+          `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td></tr>`,
+      )
+      .join('\n');
+
+    const itemList = event.order.items
+      .map((item) => `- ${item.name} x${item.quantity} @ $${item.unitPrice.toFixed(2)}`)
+      .join('\n');
+
+    const htmlBody = [
+      `<h1>Order Confirmation</h1>`,
+      `<p>Hi ${event.user.name},</p>`,
+      `<p>Thank you for your order <strong>${event.order.id}</strong>.</p>`,
+      `<table><thead><tr><th>Item</th><th>Qty</th><th>Price</th></tr></thead>`,
+      `<tbody>${itemRows}</tbody></table>`,
+      `<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>`,
+    ].join('\n');
+
+    const plainBody = [
+      `Order Confirmation`,
+      ``,
+      `Hi ${event.user.name},`,
+      ``,
+      `Thank you for your order ${event.order.id}.`,
+      ``,
+      `Items:`,
+      itemList,
+      ``,
+      `Total: $${event.order.total.toFixed(2)}`,
+    ].join('\n');
+
+    this.sendEmail({
+      to: event.user.email,
+      subject: `Order Confirmation - ${event.order.id}`,
+      htmlBody,
+      plainBody,
+    });
+  }
+
+  /**
+   * Handle order status change — send a status update email.
+   */
+  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
+    this.logger.info(
+      `Sending status update email for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
+    );
+
+    const newLabel = STATUS_LABELS[event.newStatus] ?? event.newStatus;
+    const prevLabel = STATUS_LABELS[event.previousStatus] ?? event.previousStatus;
+    const statusMessage = this.getStatusMessage(event.newStatus, event.order.id);
+
+    const htmlBody = [
+      `<h1>Order Status Update</h1>`,
+      `<p>Your order <strong>${event.order.id}</strong> has been updated.</p>`,
+      `<p>Status: <strong>${prevLabel}</strong> &rarr; <strong>${newLabel}</strong></p>`,
+      `<p>${statusMessage}</p>`,
+    ].join('\n');
+
+    const plainBody = [
+      `Order Status Update`,
+      ``,
+      `Your order ${event.order.id} has been updated.`,
+      `Status: ${prevLabel} -> ${newLabel}`,
+      ``,
+      statusMessage,
+    ].join('\n');
+
+    this.sendEmail({
+      to: event.order.userId,
+      subject: `Order ${event.order.id} - ${newLabel}`,
+      htmlBody,
+      plainBody,
+    });
+  }
+
+  /**
+   * Get a human-friendly message for a given order status.
+   */
+  private getStatusMessage(status: string, orderId: string): string {
+    switch (status) {
+      case 'confirmed':
+        return `Your order ${orderId} has been confirmed and is being prepared.`;
+      case 'shipped':
+        return `Your order ${orderId} has been shipped and is on its way.`;
+      case 'delivered':
+        return `Your order ${orderId} has been delivered. We hope you enjoy your purchase!`;
+      case 'cancelled':
+        return `Your order ${orderId} has been cancelled. If you have questions, please contact support.`;
+      default:
+        return `Your order ${orderId} status has been updated to ${status}.`;
+    }
+  }
+
+  /**
+   * Send an email (in-memory for this demo, matching the existing notification pattern).
+   */
+  private sendEmail(params: {
+    to: string;
+    subject: string;
+    htmlBody: string;
+    plainBody: string;
+  }): void {
+    const email: EmailMessage = {
+      id: generateEmailId(),
+      to: params.to,
+      subject: params.subject,
+      htmlBody: params.htmlBody,
+      plainBody: params.plainBody,
+      createdAt: new Date(),
+    };
+    this.sentEmails.push(email);
+    this.logger.info(`Email sent: ${email.id} to ${params.to} — "${params.subject}"`);
+  }
+
+  /** Get all sent emails. */
+  getSentEmails(): EmailMessage[] {
+    return [...this.sentEmails];
+  }
+
+  /** Get emails for a specific recipient. */
+  getEmailsForRecipient(recipient: string): EmailMessage[] {
+    return this.sentEmails.filter((e) => e.to === recipient);
+  }
+
+  /** Get the count of sent emails. */
+  getEmailCount(): number {
+    return this.sentEmails.length;
+  }
+
+  /** Clear all sent emails (useful for testing). */
+  clearEmails(): void {
+    this.sentEmails = [];
+  }
+}

